#include<bits/stdc++.h>
using namespace std;
string a,b;
int ans;
double gai,gai2;
int main(){
    cin>>gai>>a>>b;
    int lenmax=max(a.size(),b.size()),lenmin=min(a.size(),b.size());
    for(int i=0;i<lenmin;i++){
        if(a[i]==b[i]) ans++;
    }
    gai2=(lenmax-lenmin+ans)*1.0/lenmax;
    if(gai<=gai2) cout<<"yes";
    else cout<<"no";
    return 0;
}
